 1	import React, { FC } from 'react';
 2	import { Updater } from 'use-immer';
 3	
 4	import { Button, ButtonVariant, Popover, Text } from '@patternfly/react-core';
 5	import { HelpIcon, PlusCircleIcon } from '@patternfly/react-icons';
 6	import { V1NodeNetworkConfigurationPolicy } from '@types';
 7	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 8	import { OVN_BRIDGE_MAPPINGS } from '@utils/ovn/constants';
 9	
10	import PolicyFormOVSBridgeMappingExpandable from './PolicyFormOVSBridgeMappingExpandable';
11	
12	type PolicyFormOVSBridgeMappingProps = {
13	  policy: V1NodeNetworkConfigurationPolicy;
14	  setPolicy: Updater<V1NodeNetworkConfigurationPolicy>;
15	};
16	
17	const PolicyFormOVSBridgeMapping: FC<PolicyFormOVSBridgeMappingProps> = ({ policy, setPolicy }) => {
18	  const { t } = useNMStateTranslation();
19	
20	  return (
21	    <div>
22	      <Text className="pf-u-primary-color-100 pf-u-font-weight-bold pf-u-font-size-lg">
23	        {t('Open vSwitch bridge mapping')}{' '}
24	        <Popover
25	          aria-label={'Help'}
26	          bodyContent={t(
27	            'The Open vSwitch bridge mapping is a list of Open vSwitch bridges and the physical interfaces that are connected to them.',
28	          )}
29	        >
30	          <HelpIcon />
31	        </Popover>
32	      </Text>
33	      <Text className="policy-form-content__add-new-interface pf-u-mt-md">
34	        <Button
35	          className="pf-m-link--align-left pf-u-ml-md"
36	          onClick={() =>
37	            setPolicy((draftPolicy) => {
38	              draftPolicy.spec.desiredState.ovn[OVN_BRIDGE_MAPPINGS].unshift({
39	                bridge: '',
40	                localnet: '',
41	                state: 'present',
42	              });
43	            })
44	          }
45	          variant={ButtonVariant.link}
46	        >
47	          <PlusCircleIcon /> <span className="pf-u-ml-sm">{t('Add mapping')}</span>
48	        </Button>
49	      </Text>
50	      <PolicyFormOVSBridgeMappingExpandable policy={policy} setPolicy={setPolicy} />
51	    </div>
52	  );
53	};
54	
55	export default PolicyFormOVSBridgeMapping;

